#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
 int data;
 struct Node* next;
} Node;

void reverse_list(Node** head) {
 Node* prev = NULL;
 Node* current = *head;
 Node* next_node = NULL;

 while (current) {
 next_node = current->next;
 current->next = prev;
 prev = current;
 current = next_node;
 }

 *head = prev;
}

// Example usage:
int main() {
 Node* head = (Node*)malloc(sizeof(Node));
 head->data = 1;
 head->next = (Node*)malloc(sizeof(Node));
 head->next->data = 2;
 head->next->next = (Node*)malloc(sizeof(Node));
 head->next->next->data = 3;
 head->next->next->next = NULL;

 reverse_list(&head);

 return 0;
}
